// Always read chat_id and user_query from Extract Inputs node
const chatId = String($('Extract Inputs').first().json.chat_id || '');
const userQuery = $('Extract Inputs').first().json.user_query || '';

const now = new Date();
const isPromoActive = (promo) => {
  const fromOk = !promo.valid_from || new Date(promo.valid_from) <= now;
  const untilOk = !promo.valid_until || new Date(promo.valid_until) >= now;
  return fromOk && untilOk;
};

// Filter promotions by date validity (supports open-ended validity)
const promotions = $('Get Active Promotions').all()
  .map(i => i.json)
  .filter(p => p && isPromoActive(p));

// Get order history - guard against empty
const orderHistory = $('Get User Order History').all()
  .map(i => i.json)
  .filter(i => i && i.order_id);

// Get past items and calculate frequency
const pastItems = $('Get User Past Items').all()
  .map(i => i.json)
  .filter(i => i && i.name);

const itemFrequency = {};
pastItems.forEach(item => {
  itemFrequency[item.name] = (itemFrequency[item.name] || 0) + Number(item.quantity || 1);
});
const topItems = Object.entries(itemFrequency)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 5)
  .map(([name, qty]) => `${name} (ordered ${qty} times)`);

// Format promotions
const promoText = promotions.length > 0
  ? promotions.map(p => {
      const scopeLabel = p.promo_scope === 'product'
        ? `on product SKU: ${p.target_sku}`
        : p.promo_scope === 'category'
        ? `on all ${p.target_category} items`
        : 'on the entire order';
      const discountLabel = p.discount_type === 'percentage'
        ? `${p.discount_value}% off`
        : p.discount_type === 'flat'
        ? `flat ₹${p.discount_value} off`
        : 'Buy 2 Get 1 Free';
      return `- ${p.promo_code}: ${p.description} (${discountLabel} ${scopeLabel})`;
    }).join('\n')
  : 'No active promotions at the moment.';

const historyText = orderHistory.length > 0
  ? `Customer has placed ${orderHistory.length} previous order(s). Total spend: ₹${orderHistory.reduce((s, o) => s + parseFloat(o.final_order_total || 0), 0).toFixed(2)}`
  : 'New customer with no previous orders.';

const topItemsText = topItems.length > 0
  ? `Frequently orders: ${topItems.join(', ')}`
  : 'No purchase history yet.';

const prompt = `You are Dukaan Dost, a friendly Kirana store assistant.\n\nCustomer message: \"${userQuery}\"\n\nCustomer profile:\n- ${historyText}\n- ${topItemsText}\n\nActive promotions:\n${promoText}\n\nYour task:\n1. Understand what the customer is asking about\n2. Match relevant promotions to their query and purchase history\n3. Write a friendly, natural, short response recommending the best offers\n4. If nothing matches, mention what offers are available generally\n5. Plain text only, no markdown, no asterisks, under 80 words\n\nWrite only the message to send. Nothing else.`;

return [{ json: { prompt, chat_id: chatId } }];

const chatId = $('Build Claude Prompt').first().json.chat_id;
const aiResponse = $input.first().json.text || '';
const payload = {
  confirmation_message: aiResponse,
  chat_id: String(chatId),
};
return [{ json: payload }];

